window.PARASITIC_QUESTIONS=[{"id":"Q001","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 167","question":{"en":"Which statement best defines a parasite?","ar":"أي عبارة تُعرّف الطفيل بصورة أدق؟"},"options":[{"letter":"A","en":"An organism that depends on a host for survival, nourishment, or reproduction","ar":"كائن يعتمد على عائل للبقاء أو التغذية أو التكاثر"},{"letter":"B","en":"A free-living organism that never uses a host","ar":"كائن حر لا يستخدم عائلًا"},{"letter":"C","en":"A nonliving toxin","ar":"سم غير حي"},{"letter":"D","en":"A normal human cell","ar":"خلية بشرية طبيعية"}],"correct":"A","explanation":{"en":"A parasite derives essential benefit from another organism called the host.","ar":"يحصل الطفيل على منفعة أساسية من كائن آخر يُسمى العائل."},"reasoning":{"en":"The decisive clue is dependence on a host. This supports An organism that depends on a host for survival, nourishment, or reproduction and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الاعتماد على عائل؛ ولذلك تدعم الإجابة «كائن يعتمد على عائل للبقاء أو التغذية أو التكاثر» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q002","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 167","question":{"en":"Which group consists of external parasites such as mites and lice?","ar":"أي مجموعة تضم الطفيليات الخارجية مثل العث والقمل؟"},"options":[{"letter":"A","en":"Protozoa","ar":"الأوليات"},{"letter":"B","en":"Ectoparasites","ar":"الطفيليات الخارجية"},{"letter":"C","en":"Helminths","ar":"الديدان"},{"letter":"D","en":"Viruses","ar":"الفيروسات"}],"correct":"B","explanation":{"en":"Mites and lice live on the body surface and are classified as ectoparasites.","ar":"يعيش العث والقمل على سطح الجسم ويُصنفان كطفيليات خارجية."},"reasoning":{"en":"The decisive clue is the parasites live on the skin or hair. This supports Ectoparasites and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي وجود الطفيل على الجلد أو الشعر؛ ولذلك تدعم الإجابة «الطفيليات الخارجية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q003","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 167","question":{"en":"Which is a recognized route of parasitic transmission?","ar":"أي مما يلي طريق معروف لانتقال العدوى الطفيلية؟"},"options":[{"letter":"A","en":"Only genetic inheritance","ar":"الوراثة فقط"},{"letter":"B","en":"Only ultraviolet light","ar":"الأشعة فوق البنفسجية فقط"},{"letter":"C","en":"Vector bites, contaminated food or water, skin contact, or sexual contact","ar":"لدغات النواقل أو الطعام والماء الملوثان أو ملامسة الجلد أو الاتصال الجنسي"},{"letter":"D","en":"Only autoimmune spread","ar":"الانتشار المناعي الذاتي فقط"}],"correct":"C","explanation":{"en":"Parasitic diseases use several routes depending on the organism and its life cycle.","ar":"تنتقل الأمراض الطفيلية بطرق متعددة حسب نوع الكائن ودورة حياته."},"reasoning":{"en":"The decisive clue is multiple organism-specific transmission routes. This supports Vector bites, contaminated food or water, skin contact, or sexual contact and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تعدد طرق الانتقال حسب الطفيل؛ ولذلك تدعم الإجابة «لدغات النواقل أو الطعام والماء الملوثان أو ملامسة الجلد أو الاتصال الجنسي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q004","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 167","question":{"en":"Which disease is transmitted by the bite of an infected female sandfly?","ar":"أي مرض ينتقل بلدغة أنثى ذبابة الرمل المصابة؟"},"options":[{"letter":"A","en":"Scabies","ar":"الجرب"},{"letter":"B","en":"Head lice","ar":"قمل الرأس"},{"letter":"C","en":"Cutaneous larva migrans by direct human contact","ar":"هجرة اليرقات الجلدية بالاتصال البشري المباشر"},{"letter":"D","en":"Leishmaniasis","ar":"داء الليشمانيات"}],"correct":"D","explanation":{"en":"Leishmania is inoculated by infected female phlebotomine sandflies.","ar":"تُنقل الليشمانيا بواسطة إناث ذباب الرمل الفليبوتومي المصابة."},"reasoning":{"en":"The decisive clue is the sandfly vector. This supports Leishmaniasis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي ناقل ذبابة الرمل؛ ولذلك تدعم الإجابة «داء الليشمانيات» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q005","topic":"general","topicEn":"General Principles","topicAr":"المبادئ العامة","type":"MCQ","difficulty":"Easy","source":"PDF p. 167","question":{"en":"Why must antiparasitic therapy be selected for the specific organism and life stage?","ar":"لماذا يجب اختيار العلاج المضاد للطفيليات حسب الكائن ومرحلة دورة حياته؟"},"options":[{"letter":"A","en":"Different drugs act on different parasites and developmental stages","ar":"لأن الأدوية المختلفة تستهدف طفيليات ومراحل نمو مختلفة"},{"letter":"B","en":"All parasites respond identically to one drug","ar":"كل الطفيليات تستجيب لدواء واحد بالطريقة نفسها"},{"letter":"C","en":"Treatment is based only on skin color","ar":"يعتمد العلاج فقط على لون الجلد"},{"letter":"D","en":"Life stage never affects efficacy","ar":"مرحلة الحياة لا تؤثر في الفعالية"}],"correct":"A","explanation":{"en":"Drug activity varies by parasite biology and stage, so precise identification improves efficacy and safety.","ar":"تختلف فعالية الدواء حسب بيولوجيا الطفيل ومرحلته، لذا يحسن التحديد الدقيق الفعالية والأمان."},"reasoning":{"en":"The decisive clue is stage-specific pharmacotherapy. This supports Different drugs act on different parasites and developmental stages and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العلاج الموجه لمرحلة الطفيل؛ ولذلك تدعم الإجابة «لأن الأدوية المختلفة تستهدف طفيليات ومراحل نمو مختلفة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q006","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 168","question":{"en":"Where does the fertilized female Sarcoptes scabiei primarily burrow?","ar":"أين تحفر أنثى ساركوبتس سكابي المخصبة أساسًا؟"},"options":[{"letter":"A","en":"The dermal blood vessels","ar":"الأوعية الدموية بالأدمة"},{"letter":"B","en":"The stratum corneum","ar":"الطبقة القرنية"},{"letter":"C","en":"The subcutaneous fat","ar":"الدهون تحت الجلد"},{"letter":"D","en":"The nail matrix only","ar":"مصفوفة الظفر فقط"}],"correct":"B","explanation":{"en":"The female mite tunnels within the superficial stratum corneum to lay eggs.","ar":"تحفر الأنثى داخل الطبقة القرنية السطحية لوضع البيض."},"reasoning":{"en":"The decisive clue is a superficial epidermal burrow. This supports The stratum corneum and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي نفق سطحي داخل البشرة؛ ولذلك تدعم الإجابة «الطبقة القرنية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q007","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 168","question":{"en":"What immune mechanism is mainly responsible for the pruritic scabies rash?","ar":"ما الآلية المناعية الأساسية المسؤولة عن طفح الجرب الحاك؟"},"options":[{"letter":"A","en":"Immediate IgE reaction to pollen only","ar":"تفاعل IgE فوري لحبوب اللقاح فقط"},{"letter":"B","en":"Antibody-mediated hemolysis","ar":"انحلال دم بوساطة الأجسام المضادة"},{"letter":"C","en":"Delayed type IV hypersensitivity to mite antigens and scybala","ar":"فرط حساسية متأخر من النوع الرابع لمستضدات العثة وفضلاتها"},{"letter":"D","en":"Immune-complex nephritis as the primary lesion","ar":"التهاب كلى بمعقدات مناعية كآفة أولية"}],"correct":"C","explanation":{"en":"Mite saliva, eggs, and fecal pellets trigger a delayed cellular hypersensitivity response.","ar":"تثير لعاب العثة وبيضها وفضلاتها استجابة فرط حساسية خلوية متأخرة."},"reasoning":{"en":"The decisive clue is the delayed sensitization period. This supports Delayed type IV hypersensitivity to mite antigens and scybala and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي فترة التحسس المتأخرة؛ ولذلك تدعم الإجابة «فرط حساسية متأخر من النوع الرابع لمستضدات العثة وفضلاتها» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q008","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 169","question":{"en":"What is the usual incubation before symptoms in a first scabies infestation?","ar":"ما فترة الحضانة المعتادة قبل ظهور الأعراض في الإصابة الأولى بالجرب؟"},"options":[{"letter":"A","en":"Ten minutes","ar":"عشر دقائق"},{"letter":"B","en":"One day in every patient","ar":"يوم واحد في كل المرضى"},{"letter":"C","en":"One year","ar":"سنة كاملة"},{"letter":"D","en":"About 3–6 weeks","ar":"نحو 3–6 أسابيع"}],"correct":"D","explanation":{"en":"Primary infestation requires weeks for sensitization to mite antigens.","ar":"تحتاج الإصابة الأولى أسابيع حتى يحدث التحسس لمستضدات العثة."},"reasoning":{"en":"The decisive clue is first exposure without prior sensitization. This supports About 3–6 weeks and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التعرض الأول دون تحسس سابق؛ ولذلك تدعم الإجابة «نحو 3–6 أسابيع» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q009","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 169","question":{"en":"How quickly may symptoms appear after scabies reinfestation?","ar":"ما سرعة ظهور الأعراض عند إعادة الإصابة بالجرب؟"},"options":[{"letter":"A","en":"Within about 1–4 days","ar":"خلال نحو 1–4 أيام"},{"letter":"B","en":"Only after six months","ar":"بعد ستة أشهر فقط"},{"letter":"C","en":"Always after 3–6 weeks","ar":"دائمًا بعد 3–6 أسابيع"},{"letter":"D","en":"Immediately within seconds","ar":"فورًا خلال ثوانٍ"}],"correct":"A","explanation":{"en":"Previously sensitized patients mount a much faster immune response.","ar":"يُظهر المريض المتحسس سابقًا استجابة مناعية أسرع بكثير."},"reasoning":{"en":"The decisive clue is prior immune priming. This supports Within about 1–4 days and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التهيئة المناعية السابقة؛ ولذلك تدعم الإجابة «خلال نحو 1–4 أيام» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q010","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 169","question":{"en":"Which symptom is most characteristic of classic scabies?","ar":"أي عرض هو الأكثر تميزًا للجرب التقليدي؟"},"options":[{"letter":"A","en":"Painless jaundice","ar":"يرقان غير مؤلم"},{"letter":"B","en":"Severe itching that worsens at night","ar":"حكة شديدة تزداد ليلًا"},{"letter":"C","en":"Isolated hair loss without itch","ar":"تساقط شعر منفرد دون حكة"},{"letter":"D","en":"Persistent high fever as the only sign","ar":"حمى مرتفعة مستمرة كعلامة وحيدة"}],"correct":"B","explanation":{"en":"Intense nocturnal pruritus is the hallmark symptom of scabies.","ar":"الحكة الليلية الشديدة هي العرض المميز للجرب."},"reasoning":{"en":"The decisive clue is night-time exacerbation of itch. This supports Severe itching that worsens at night and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي زيادة الحكة ليلًا؛ ولذلك تدعم الإجابة «حكة شديدة تزداد ليلًا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q011","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 169","question":{"en":"Which primary lesion is considered pathognomonic for scabies?","ar":"أي آفة أولية تُعد نوعية للجرب؟"},"options":[{"letter":"A","en":"A honey-colored crust","ar":"قشرة بلون العسل"},{"letter":"B","en":"A target lesion","ar":"آفة هدفية"},{"letter":"C","en":"A fine serpiginous burrow","ar":"نفق رفيع متعرج"},{"letter":"D","en":"A dermatomal vesicle cluster","ar":"تجمع حويصلات على قطاع عصبي"}],"correct":"C","explanation":{"en":"Burrows represent the track created by the female mite in the stratum corneum.","ar":"تمثل الأنفاق المسار الذي تصنعه أنثى العثة داخل الطبقة القرنية."},"reasoning":{"en":"The decisive clue is a 5–20 mm thread-like track. This supports A fine serpiginous burrow and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي مسار خيطي بطول 5–20 مم؛ ولذلك تدعم الإجابة «نفق رفيع متعرج» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q012","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 169","question":{"en":"Which site is typical in a healthy adult with scabies?","ar":"أي موضع نموذجي للجرب لدى بالغ سليم؟"},"options":[{"letter":"A","en":"Only the central back","ar":"منتصف الظهر فقط"},{"letter":"B","en":"Only the scalp","ar":"فروة الرأس فقط"},{"letter":"C","en":"Only the tongue","ar":"اللسان فقط"},{"letter":"D","en":"Finger webs and volar wrists","ar":"بين الأصابع والسطح الراحي للرسغ"}],"correct":"D","explanation":{"en":"Finger webs, wrists, axillae, waistline, areolae, and genital areas are common adult sites.","ar":"تشيع الإصابة بين الأصابع والرسغين والإبطين والخصر والهالات والمنطقة التناسلية لدى البالغين."},"reasoning":{"en":"The decisive clue is the classic acral and flexural distribution. This supports Finger webs and volar wrists and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التوزيع الطرفي والثني الكلاسيكي؛ ولذلك تدعم الإجابة «بين الأصابع والسطح الراحي للرسغ» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q013","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 169","question":{"en":"Which distribution is especially important in infants and elderly patients with scabies?","ar":"أي توزيع مهم خاصة لدى الرضع وكبار السن المصابين بالجرب؟"},"options":[{"letter":"A","en":"Palms, soles, scalp, face, and neck may be involved","ar":"قد تشمل الآفات الراحتين والأخمصين وفروة الرأس والوجه والعنق"},{"letter":"B","en":"The head is always spared","ar":"يُستثنى الرأس دائمًا"},{"letter":"C","en":"Only the nails are affected","ar":"تُصاب الأظافر فقط"},{"letter":"D","en":"Only one toe is affected","ar":"يُصاب إصبع قدم واحد فقط"}],"correct":"A","explanation":{"en":"Age extremes may show head, neck, palm, and sole involvement that is unusual in healthy adults.","ar":"قد تظهر لدى طرفي العمر إصابة الرأس والعنق والراحتين والأخمصين خلافًا للبالغين الأصحاء."},"reasoning":{"en":"The decisive clue is the atypical age-related distribution. This supports Palms, soles, scalp, face, and neck may be involved and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التوزيع غير النمطي المرتبط بالعمر؛ ولذلك تدعم الإجابة «قد تشمل الآفات الراحتين والأخمصين وفروة الرأس والوجه والعنق» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q014","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 170","question":{"en":"Which feature favors zoonotic scabies acquired from an animal?","ar":"أي علامة ترجح الجرب الحيواني المنشأ؟"},"options":[{"letter":"A","en":"Persistent human-to-human outbreaks","ar":"تفشيات بشرية مستمرة"},{"letter":"B","en":"Short self-limited illness with lesions at contact sites and no burrows","ar":"مرض قصير محدود ذاتيًا مع آفات في مواضع التلامس دون أنفاق"},{"letter":"C","en":"Millions of mites with thick crusts","ar":"ملايين العث مع قشور سميكة"},{"letter":"D","en":"Classic genital nodules for months","ar":"عقيدات تناسلية كلاسيكية لأشهر"}],"correct":"B","explanation":{"en":"Animal mites cause transient papules but do not reproduce effectively on humans or spread person to person.","ar":"تسبب عث الحيوانات حطاطات عابرة لكنها لا تتكاثر بفاعلية على الإنسان ولا تنتقل بين البشر."},"reasoning":{"en":"The decisive clue is animal contact plus absent burrows. This supports Short self-limited illness with lesions at contact sites and no burrows and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي ملامسة حيوان مع غياب الأنفاق؛ ولذلك تدعم الإجابة «مرض قصير محدود ذاتيًا مع آفات في مواضع التلامس دون أنفاق» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q015","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 170","question":{"en":"What causes scabies incognito?","ar":"ما سبب الجرب المتخفي؟"},"options":[{"letter":"A","en":"A mutation that eliminates all mites","ar":"طفرة تقضي على كل العث"},{"letter":"B","en":"Antibiotic treatment","ar":"العلاج بالمضادات الحيوية"},{"letter":"C","en":"Inappropriate corticosteroid use that suppresses typical inflammation","ar":"استخدام الكورتيكوستيرويدات بصورة غير مناسبة بما يثبط الالتهاب المعتاد"},{"letter":"D","en":"Sun exposure alone","ar":"التعرض للشمس فقط"}],"correct":"C","explanation":{"en":"Steroids mask itching and typical lesions while the infestation persists and spreads.","ar":"تخفي الستيرويدات الحكة والآفات النموذجية بينما تستمر الإصابة وتنتشر."},"reasoning":{"en":"The decisive clue is temporary improvement after steroid use. This supports Inappropriate corticosteroid use that suppresses typical inflammation and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تحسن مؤقت بعد الستيرويد؛ ولذلك تدعم الإجابة «استخدام الكورتيكوستيرويدات بصورة غير مناسبة بما يثبط الالتهاب المعتاد» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q016","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 171","question":{"en":"Which patient is at greatest risk of crusted scabies?","ar":"أي مريض أكثر عرضة للجرب المتقشر؟"},"options":[{"letter":"A","en":"A healthy athlete with one insect bite","ar":"رياضي سليم لديه لدغة واحدة"},{"letter":"B","en":"A patient with seasonal rhinitis","ar":"مريض حساسية أنفية موسمية"},{"letter":"C","en":"A patient with a simple wart","ar":"مريض لديه ثؤلول بسيط"},{"letter":"D","en":"An immunosuppressed or neurologically impaired patient unable to scratch effectively","ar":"مريض مثبط المناعة أو لديه خلل عصبي يمنعه من الحك بفاعلية"}],"correct":"D","explanation":{"en":"Crusted scabies develops when host defense or scratching cannot control a massive mite burden.","ar":"ينشأ الجرب المتقشر عندما يعجز دفاع العائل أو الحك عن ضبط الحمل الهائل من العث."},"reasoning":{"en":"The decisive clue is thick hyperkeratotic crusts in a high-risk host. This supports An immunosuppressed or neurologically impaired patient unable to scratch effectively and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قشور سميكة مفرطة التقرن لدى عائل عالي الخطورة؛ ولذلك تدعم الإجابة «مريض مثبط المناعة أو لديه خلل عصبي يمنعه من الحك بفاعلية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q017","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 171","question":{"en":"What best explains persistent nodular scabies after mites have been eradicated?","ar":"ما أفضل تفسير لاستمرار عقيدات الجرب بعد القضاء على العث؟"},"options":[{"letter":"A","en":"Persistent hypersensitivity to retained mite antigens","ar":"استمرار فرط الحساسية لمستضدات العث المتبقية"},{"letter":"B","en":"Guaranteed treatment failure","ar":"فشل العلاج المؤكد"},{"letter":"C","en":"A fungal nail infection","ar":"عدوى فطرية بالأظافر"},{"letter":"D","en":"A new viral exanthem","ar":"طفح فيروسي جديد"}],"correct":"A","explanation":{"en":"Nodules may remain for weeks or months because inflammation outlasts the living mites.","ar":"قد تستمر العقيدات أسابيع أو أشهر لأن الالتهاب يستمر بعد موت العث."},"reasoning":{"en":"The decisive clue is persistent pruritic genital or axillary nodules despite eradication. This supports Persistent hypersensitivity to retained mite antigens and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي استمرار عقيدات حاكة تناسلية أو إبطيّة رغم القضاء على العث؛ ولذلك تدعم الإجابة «استمرار فرط الحساسية لمستضدات العث المتبقية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q018","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 171","question":{"en":"What characterizes “scabies in the clean”?","ar":"ما الذي يميز «الجرب لدى شديدي النظافة»؟"},"options":[{"letter":"A","en":"No itching and massive crusts","ar":"لا حكة مع قشور هائلة"},{"letter":"B","en":"Few subtle lesions despite intense pruritus","ar":"آفات قليلة وخفية رغم الحكة الشديدة"},{"letter":"C","en":"Only systemic fever","ar":"حمى جهازية فقط"},{"letter":"D","en":"Permanent immunity","ar":"مناعة دائمة"}],"correct":"B","explanation":{"en":"Frequent bathing can reduce visible lesions but does not eliminate the infestation or itch.","ar":"قد يقلل الاستحمام المتكرر الآفات الظاهرة لكنه لا يقضي على الإصابة أو الحكة."},"reasoning":{"en":"The decisive clue is severe itch with sparse findings. This supports Few subtle lesions despite intense pruritus and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حكة شديدة مع علامات قليلة؛ ولذلك تدعم الإجابة «آفات قليلة وخفية رغم الحكة الشديدة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q019","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 172","question":{"en":"How long should permethrin 5% cream usually remain on the skin for classic scabies?","ar":"كم ينبغي عادةً أن يبقى كريم بيرمثرين 5% على الجلد لعلاج الجرب التقليدي؟"},"options":[{"letter":"A","en":"Thirty seconds","ar":"ثلاثون ثانية"},{"letter":"B","en":"Forty-eight hours continuously","ar":"ثمانٍ وأربعون ساعة متواصلة"},{"letter":"C","en":"Eight to fourteen hours","ar":"ثماني إلى أربع عشرة ساعة"},{"letter":"D","en":"One month","ar":"شهر كامل"}],"correct":"C","explanation":{"en":"Permethrin is applied thoroughly and washed off after 8–14 hours.","ar":"يُوضع البيرمثرين جيدًا ثم يُغسل بعد 8–14 ساعة."},"reasoning":{"en":"The decisive clue is the overnight whole-body application. This supports Eight to fourteen hours and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التطبيق الليلي على كامل الجسم؛ ولذلك تدعم الإجابة «ثماني إلى أربع عشرة ساعة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q020","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Easy","source":"PDF p. 172","question":{"en":"Which statement about permethrin 5% is correct?","ar":"أي عبارة صحيحة عن بيرمثرين 5%؟"},"options":[{"letter":"A","en":"It is contraindicated in every child","ar":"ممنوع لدى كل الأطفال"},{"letter":"B","en":"It must never be repeated","ar":"لا يُكرر أبدًا"},{"letter":"C","en":"It is applied only to visible papules","ar":"يوضع فقط على الحطاطات الظاهرة"},{"letter":"D","en":"It can be used from 2 months of age and is preferred in pregnancy and lactation","ar":"يمكن استخدامه من عمر شهرين ويُفضل في الحمل والرضاعة"}],"correct":"D","explanation":{"en":"Low systemic absorption and extensive experience support permethrin in these populations.","ar":"يدعم الامتصاص الجهازي المنخفض والخبرة الواسعة استخدام البيرمثرين في هذه الفئات."},"reasoning":{"en":"The decisive clue is age and pregnancy safety. This supports It can be used from 2 months of age and is preferred in pregnancy and lactation and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الأمان حسب العمر والحمل؛ ولذلك تدعم الإجابة «يمكن استخدامه من عمر شهرين ويُفضل في الحمل والرضاعة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q021","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Medium","source":"PDF p. 174","question":{"en":"What is preferred for scabies in an infant younger than 2 months?","ar":"ما العلاج المفضل للجرب لدى رضيع أصغر من شهرين؟"},"options":[{"letter":"A","en":"Topical sulfur","ar":"الكبريت الموضعي"},{"letter":"B","en":"Oral ivermectin","ar":"إيفرمكتين فموي"},{"letter":"C","en":"Lindane","ar":"ليندان"},{"letter":"D","en":"High-dose systemic steroid alone","ar":"ستيرويد جهازي عالي الجرعة فقط"}],"correct":"A","explanation":{"en":"Sulfur is used because permethrin is not approved below two months and oral ivermectin is unsuitable.","ar":"يُستخدم الكبريت لأن البيرمثرين غير معتمد تحت عمر شهرين ولأن الإيفرمكتين الفموي غير مناسب."},"reasoning":{"en":"The decisive clue is the neonatal age limit. This supports Topical sulfur and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي حد العمر في حديثي الولادة؛ ولذلك تدعم الإجابة «الكبريت الموضعي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q022","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Medium","source":"PDF p. 174","question":{"en":"What is the recommended core treatment for crusted scabies?","ar":"ما العلاج الأساسي الموصى به للجرب المتقشر؟"},"options":[{"letter":"A","en":"Antihistamine alone","ar":"مضاد هيستامين فقط"},{"letter":"B","en":"Topical permethrin plus repeated oral ivermectin","ar":"بيرمثرين موضعي مع جرعات متكررة من الإيفرمكتين الفموي"},{"letter":"C","en":"Single topical steroid dose","ar":"جرعة ستيرويد موضعي واحدة"},{"letter":"D","en":"Observation without contact treatment","ar":"الملاحظة دون علاج المخالطين"}],"correct":"B","explanation":{"en":"The enormous mite burden requires combined topical and systemic scabicidal therapy.","ar":"يتطلب الحمل الهائل من العث علاجًا قاتلًا للجرب موضعيًا وجهازيًا معًا."},"reasoning":{"en":"The decisive clue is hyperinfestation with millions of mites. This supports Topical permethrin plus repeated oral ivermectin and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي فرط الإصابة بملايين العث؛ ولذلك تدعم الإجابة «بيرمثرين موضعي مع جرعات متكررة من الإيفرمكتين الفموي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q023","topic":"scabies","topicEn":"Scabies","topicAr":"الجرب","type":"MCQ","difficulty":"Medium","source":"PDF p. 174","question":{"en":"In which situation is oral ivermectin generally not recommended?","ar":"في أي حالة لا يُوصى عادةً بالإيفرمكتين الفموي؟"},"options":[{"letter":"A","en":"A healthy adult over 70 kg","ar":"بالغ سليم فوق 70 كجم"},{"letter":"B","en":"Crusted scabies under specialist care","ar":"الجرب المتقشر تحت إشراف مختص"},{"letter":"C","en":"Pregnancy or body weight below 15 kg","ar":"الحمل أو وزن أقل من 15 كجم"},{"letter":"D","en":"Failure of correctly applied topical therapy in an eligible adult","ar":"فشل العلاج الموضعي الصحيح لدى بالغ مناسب"}],"correct":"C","explanation":{"en":"Safety is not established in pregnancy or in children under 15 kg.","ar":"لم يثبت أمانه في الحمل أو لدى الأطفال أقل من 15 كجم."},"reasoning":{"en":"The decisive clue is the safety restrictions. This supports Pregnancy or body weight below 15 kg and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قيود الأمان؛ ولذلك تدعم الإجابة «الحمل أو وزن أقل من 15 كجم» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q024","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 176","question":{"en":"Which organism causes head lice infestation?","ar":"أي كائن يسبب قمل الرأس؟"},"options":[{"letter":"A","en":"Pthirus pubis","ar":"فثيروس بوبس"},{"letter":"B","en":"Sarcoptes scabiei","ar":"ساركوبتس سكابي"},{"letter":"C","en":"Leishmania major","ar":"ليشمانيا ميجور"},{"letter":"D","en":"Pediculus humanus capitis","ar":"بيديكولوس هيومانوس كابيتس"}],"correct":"D","explanation":{"en":"Pediculus humanus capitis is adapted to the scalp and hair.","ar":"يتكيف بيديكولوس هيومانوس كابيتس مع فروة الرأس والشعر."},"reasoning":{"en":"The decisive clue is the scalp-specific louse. This supports Pediculus humanus capitis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القملة الخاصة بفروة الرأس؛ ولذلك تدعم الإجابة «بيديكولوس هيومانوس كابيتس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q025","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 177","question":{"en":"Which finding best distinguishes viable head-lice nits from dandruff?","ar":"أي علامة تميز صئبان قمل الرأس عن القشرة؟"},"options":[{"letter":"A","en":"Nits are firmly attached to the hair shaft near the scalp","ar":"تلتصق الصئبان بقوة بساق الشعرة قرب فروة الرأس"},{"letter":"B","en":"Nits brush away easily","ar":"تسقط الصئبان بسهولة بالتمشيط"},{"letter":"C","en":"Nits are found only on clothing seams","ar":"توجد الصئبان فقط في درزات الملابس"},{"letter":"D","en":"Nits fluoresce green under Wood lamp","ar":"تتألق الصئبان بالأخضر تحت مصباح وود"}],"correct":"A","explanation":{"en":"Louse eggs are cemented to hairs, unlike loose scale.","ar":"تلتصق بيضات القمل بالشعر بمادة لاصقة بخلاف القشور السائبة."},"reasoning":{"en":"The decisive clue is firm attachment to the hair shaft. This supports Nits are firmly attached to the hair shaft near the scalp and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الالتصاق القوي بساق الشعرة؛ ولذلك تدعم الإجابة «تلتصق الصئبان بقوة بساق الشعرة قرب فروة الرأس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q026","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 177","question":{"en":"Where are body lice and their eggs most often found?","ar":"أين يوجد قمل الجسم وبيضه غالبًا؟"},"options":[{"letter":"A","en":"Inside the dermis","ar":"داخل الأدمة"},{"letter":"B","en":"In the seams of clothing","ar":"في درزات الملابس"},{"letter":"C","en":"Only under fingernails","ar":"تحت الأظافر فقط"},{"letter":"D","en":"Within salivary glands","ar":"داخل الغدد اللعابية"}],"correct":"B","explanation":{"en":"Body lice live and lay eggs in clothing and move to the skin to feed.","ar":"يعيش قمل الجسم ويضع البيض في الملابس ثم ينتقل إلى الجلد للتغذية."},"reasoning":{"en":"The decisive clue is infested clothing seams. This supports In the seams of clothing and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي درزات الملابس المصابة؛ ولذلك تدعم الإجابة «في درزات الملابس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q027","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 177","question":{"en":"Which lesion is particularly associated with pubic lice?","ar":"أي آفة ترتبط بصورة خاصة بقمل العانة؟"},"options":[{"letter":"A","en":"Koplik spots","ar":"بقع كوبليك"},{"letter":"B","en":"Honey-colored crusts only","ar":"قشور بلون العسل فقط"},{"letter":"C","en":"Maculae ceruleae","ar":"البقع الزرقاء الرمادية"},{"letter":"D","en":"A dermatomal vesicular band","ar":"شريط حويصلي قطعي"}],"correct":"C","explanation":{"en":"Bluish-gray macules at bite sites result from blood-pigment deposition.","ar":"تنشأ البقع الزرقاء الرمادية في مواضع اللدغ بسبب ترسب صبغات الدم."},"reasoning":{"en":"The decisive clue is bluish-gray bite-site macules. This supports Maculae ceruleae and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي بقع زرقاء رمادية في مواضع اللدغ؛ ولذلك تدعم الإجابة «البقع الزرقاء الرمادية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q028","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 178","question":{"en":"Which infection may be transmitted by body lice?","ar":"أي عدوى قد ينقلها قمل الجسم؟"},"options":[{"letter":"A","en":"Varicella","ar":"الجديري المائي"},{"letter":"B","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"C","en":"Scabies","ar":"الجرب"},{"letter":"D","en":"Epidemic typhus due to Rickettsia prowazekii","ar":"التيفوس الوبائي بسبب ريكتسيا بروفازيكي"}],"correct":"D","explanation":{"en":"Body lice are vectors of Rickettsia prowazekii.","ar":"قمل الجسم ناقل لريكتسيا بروفازيكي."},"reasoning":{"en":"The decisive clue is the louse-borne rickettsial disease. This supports Epidemic typhus due to Rickettsia prowazekii and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي المرض الريكتسي المنقول بالقمل؛ ولذلك تدعم الإجابة «التيفوس الوبائي بسبب ريكتسيا بروفازيكي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q029","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 178","question":{"en":"Which pathogen causes louse-borne relapsing fever?","ar":"أي ممرض يسبب الحمى الراجعة المنقولة بالقمل؟"},"options":[{"letter":"A","en":"Borrelia recurrentis","ar":"بوريليا ريكورنتس"},{"letter":"B","en":"Bartonella henselae","ar":"بارتونيلا هنسلي"},{"letter":"C","en":"Candida albicans","ar":"كانديدا ألبيكانس"},{"letter":"D","en":"Staphylococcus epidermidis","ar":"ستافيلوكوكس إيبيدرميدس"}],"correct":"A","explanation":{"en":"Borrelia recurrentis is transmitted by body lice in crowded conditions.","ar":"تنقل قملة الجسم بوريليا ريكورنتس في ظروف الازدحام."},"reasoning":{"en":"The decisive clue is the spirochetal louse-borne illness. This supports Borrelia recurrentis and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العدوى اللولبية المنقولة بالقمل؛ ولذلك تدعم الإجابة «بوريليا ريكورنتس» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q030","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 178","question":{"en":"Which organism is responsible for trench fever transmitted by body lice?","ar":"أي كائن مسؤول عن حمى الخنادق المنقولة بقمل الجسم؟"},"options":[{"letter":"A","en":"Leishmania tropica","ar":"ليشمانيا تروبيكا"},{"letter":"B","en":"Bartonella quintana","ar":"بارتونيلا كوينتانا"},{"letter":"C","en":"Sarcoptes scabiei","ar":"ساركوبتس سكابي"},{"letter":"D","en":"Ancylostoma braziliense","ar":"أنكلستوما برازيليانس"}],"correct":"B","explanation":{"en":"Bartonella quintana is a classic body-louse-borne pathogen.","ar":"بارتونيلا كوينتانا ممرض تقليدي ينقله قمل الجسم."},"reasoning":{"en":"The decisive clue is the trench-fever vector association. This supports Bartonella quintana and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي ارتباط الناقل بحمى الخنادق؛ ولذلك تدعم الإجابة «بارتونيلا كوينتانا» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q031","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 178","question":{"en":"What is the main route of head-lice transmission?","ar":"ما الطريق الرئيسي لانتقال قمل الرأس؟"},"options":[{"letter":"A","en":"Airborne spread across rooms","ar":"انتقال هوائي عبر الغرف"},{"letter":"B","en":"Mosquito bites","ar":"لدغات البعوض"},{"letter":"C","en":"Direct head-to-head contact","ar":"ملامسة الرأس للرأس مباشرةً"},{"letter":"D","en":"Contaminated drinking water","ar":"مياه الشرب الملوثة"}],"correct":"C","explanation":{"en":"Close hair-to-hair contact is substantially more efficient than indirect spread.","ar":"تُعد ملامسة الشعر للشعر أكثر كفاءة بكثير من الانتقال غير المباشر."},"reasoning":{"en":"The decisive clue is close contact among children. This supports Direct head-to-head contact and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التلامس القريب بين الأطفال؛ ولذلك تدعم الإجابة «ملامسة الرأس للرأس مباشرةً» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q032","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 179","question":{"en":"How long do lice generally survive away from a human host?","ar":"كم يعيش القمل عادةً بعيدًا عن الإنسان؟"},"options":[{"letter":"A","en":"Several months","ar":"عدة أشهر"},{"letter":"B","en":"Ten years","ar":"عشر سنوات"},{"letter":"C","en":"They never leave the host","ar":"لا يغادر العائل أبدًا"},{"letter":"D","en":"About 1–2 days","ar":"نحو يوم إلى يومين"}],"correct":"D","explanation":{"en":"Lice rapidly die without regular blood meals, limiting prolonged environmental survival.","ar":"يموت القمل سريعًا دون وجبات دم منتظمة مما يحد من بقائه في البيئة."},"reasoning":{"en":"The decisive clue is short off-host survival. This supports About 1–2 days and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قصر البقاء بعيدًا عن العائل؛ ولذلك تدعم الإجابة «نحو يوم إلى يومين» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q033","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 180","question":{"en":"From what age can permethrin 1% generally be used for head lice?","ar":"من أي عمر يمكن عادةً استخدام بيرمثرين 1% لقمل الرأس؟"},"options":[{"letter":"A","en":"Two months of age","ar":"عمر شهرين"},{"letter":"B","en":"Only after 12 years","ar":"بعد 12 سنة فقط"},{"letter":"C","en":"Only after 18 years","ar":"بعد 18 سنة فقط"},{"letter":"D","en":"From birth without restriction","ar":"منذ الولادة دون قيود"}],"correct":"A","explanation":{"en":"Permethrin 1% has an established safety record from two months of age.","ar":"يمتلك بيرمثرين 1% سجل أمان معتمدًا من عمر شهرين."},"reasoning":{"en":"The decisive clue is the labeled pediatric age. This supports Two months of age and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العمر المعتمد للأطفال؛ ولذلك تدعم الإجابة «عمر شهرين» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q034","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 180","question":{"en":"Why is a second permethrin treatment commonly given on day 9 or 10?","ar":"لماذا تُعطى جرعة ثانية من البيرمثرين غالبًا في اليوم 9 أو 10؟"},"options":[{"letter":"A","en":"To prevent fungal infection","ar":"لمنع عدوى فطرية"},{"letter":"B","en":"To kill newly hatched lice that survived as eggs","ar":"لقتل القمل الذي فقس حديثًا من بيض لم يُقض عليه"},{"letter":"C","en":"Because the first dose has no pediculicidal activity","ar":"لأن الجرعة الأولى لا تقتل القمل"},{"letter":"D","en":"To treat anemia directly","ar":"لعلاج الأنيميا مباشرةً"}],"correct":"B","explanation":{"en":"Permethrin is not fully ovicidal, so timing targets hatchlings before they reproduce.","ar":"لا يقضي البيرمثرين تمامًا على البيض، لذا يستهدف التوقيت القمل حديث الفقس قبل تكاثره."},"reasoning":{"en":"The decisive clue is the egg-hatching interval. This supports To kill newly hatched lice that survived as eggs and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي فترة فقس البيض؛ ولذلك تدعم الإجابة «لقتل القمل الذي فقس حديثًا من بيض لم يُقض عليه» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q035","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 180","question":{"en":"What is the mechanism of malathion against lice?","ar":"ما آلية عمل الملاثيون ضد القمل؟"},"options":[{"letter":"A","en":"Blocking fungal ergosterol","ar":"تثبيط إرغوستيرول الفطريات"},{"letter":"B","en":"Inhibiting bacterial cell walls","ar":"تثبيط جدار الخلية البكتيرية"},{"letter":"C","en":"Organophosphate inhibition of cholinesterase","ar":"تثبيط إنزيم الكولين إستيراز كمركب فوسفاتي عضوي"},{"letter":"D","en":"Neutralizing histamine only","ar":"معادلة الهيستامين فقط"}],"correct":"C","explanation":{"en":"Malathion is neurotoxic to lice and has pediculicidal and ovicidal activity.","ar":"الملاثيون سام عصبيًا للقمل وله فعالية ضد القمل والبيض."},"reasoning":{"en":"The decisive clue is cholinesterase inhibition. This supports Organophosphate inhibition of cholinesterase and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تثبيط الكولين إستيراز؛ ولذلك تدعم الإجابة «تثبيط إنزيم الكولين إستيراز كمركب فوسفاتي عضوي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q036","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 181","question":{"en":"Which counseling point is essential for malathion lotion?","ar":"أي نصيحة أساسية عند استخدام لوشن الملاثيون؟"},"options":[{"letter":"A","en":"Apply beside an open flame to accelerate drying","ar":"استخدامه قرب لهب لتسريع الجفاف"},{"letter":"B","en":"Use hot hair dryers immediately","ar":"استخدام مجفف ساخن فورًا"},{"letter":"C","en":"Mix it with gasoline","ar":"خلطه بالبنزين"},{"letter":"D","en":"Keep it away from flames and heat because it is highly flammable","ar":"إبعاده عن اللهب والحرارة لأنه شديد الاشتعال"}],"correct":"D","explanation":{"en":"The alcohol-based formulation is flammable and must dry away from heat sources.","ar":"التركيبة الكحولية قابلة للاشتعال ويجب أن تجف بعيدًا عن مصادر الحرارة."},"reasoning":{"en":"The decisive clue is the flammability hazard. This supports Keep it away from flames and heat because it is highly flammable and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي خطر الاشتعال؛ ولذلك تدعم الإجابة «إبعاده عن اللهب والحرارة لأنه شديد الاشتعال» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q037","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 181","question":{"en":"How does spinosad kill lice?","ar":"كيف يقتل السبينوساد القمل؟"},"options":[{"letter":"A","en":"It causes neuronal excitation and paralysis through nicotinic acetylcholine receptors","ar":"يسبب تنبيهًا عصبيًا وشللًا عبر مستقبلات النيكوتين للأستيل كولين"},{"letter":"B","en":"It dissolves keratin chemically","ar":"يذيب الكيراتين كيميائيًا"},{"letter":"C","en":"It blocks viral DNA polymerase","ar":"يثبط بوليميراز DNA الفيروسي"},{"letter":"D","en":"It acts as an antibiotic","ar":"يعمل كمضاد حيوي"}],"correct":"A","explanation":{"en":"Spinosad disrupts louse neural transmission and is effective in many resistant infestations.","ar":"يعطل السبينوساد النقل العصبي في القمل ويفيد في كثير من الإصابات المقاومة."},"reasoning":{"en":"The decisive clue is the nicotinic receptor action. This supports It causes neuronal excitation and paralysis through nicotinic acetylcholine receptors and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التأثير على مستقبلات النيكوتين؛ ولذلك تدعم الإجابة «يسبب تنبيهًا عصبيًا وشللًا عبر مستقبلات النيكوتين للأستيل كولين» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q038","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 181","question":{"en":"What is a typical regimen for topical ivermectin lotion in head lice?","ar":"ما النظام المعتاد للوشن الإيفرمكتين الموضعي لقمل الرأس؟"},"options":[{"letter":"A","en":"Daily use for six months","ar":"استخدام يومي ستة أشهر"},{"letter":"B","en":"A single 10-minute application to dry hair, then rinse","ar":"تطبيق واحد لمدة 10 دقائق على الشعر الجاف ثم الشطف"},{"letter":"C","en":"Intravenous infusion","ar":"تسريب وريدي"},{"letter":"D","en":"Application only to clothing seams","ar":"وضعه فقط على درزات الملابس"}],"correct":"B","explanation":{"en":"Topical ivermectin often works with one short application and does not require routine nit combing.","ar":"غالبًا ينجح الإيفرمكتين الموضعي بتطبيق قصير واحد ولا يحتاج عادةً إلى إزالة الصئبان."},"reasoning":{"en":"The decisive clue is the single 10-minute application. This supports A single 10-minute application to dry hair, then rinse and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي التطبيق الواحد لمدة 10 دقائق؛ ولذلك تدعم الإجابة «تطبيق واحد لمدة 10 دقائق على الشعر الجاف ثم الشطف» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q039","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 182","question":{"en":"Which patient should generally not receive oral ivermectin for head lice?","ar":"أي مريض لا ينبغي عادةً أن يتلقى الإيفرمكتين الفموي لقمل الرأس؟"},"options":[{"letter":"A","en":"An eligible adult with resistant infestation","ar":"بالغ مناسب لديه إصابة مقاومة"},{"letter":"B","en":"A patient who failed two correctly used topicals","ar":"مريض فشل معه علاجان موضعيان صحيحان"},{"letter":"C","en":"A pregnant patient or a child weighing under 15 kg","ar":"حامل أو طفل وزنه أقل من 15 كجم"},{"letter":"D","en":"A patient with normal renal function","ar":"مريض بوظيفة كلوية طبيعية"}],"correct":"C","explanation":{"en":"Safety is not established in pregnancy or in children below 15 kg.","ar":"لم يثبت الأمان في الحمل أو لدى الأطفال أقل من 15 كجم."},"reasoning":{"en":"The decisive clue is the systemic safety restriction. This supports A pregnant patient or a child weighing under 15 kg and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قيد الأمان الجهازي؛ ولذلك تدعم الإجابة «حامل أو طفل وزنه أقل من 15 كجم» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q040","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 182","question":{"en":"What is the main disadvantage of wet combing as sole treatment?","ar":"ما العيب الرئيسي لاستخدام التمشيط الرطب وحده؟"},"options":[{"letter":"A","en":"It is always neurotoxic","ar":"يسبب دائمًا سمية عصبية"},{"letter":"B","en":"It cannot remove any lice","ar":"لا يزيل أي قمل"},{"letter":"C","en":"It is contraindicated in all children","ar":"ممنوع لدى كل الأطفال"},{"letter":"D","en":"It is time-consuming and requires repeated sessions","ar":"يستغرق وقتًا ويتطلب جلسات متكررة"}],"correct":"D","explanation":{"en":"Mechanical removal can work, but it must be repeated every few days for several weeks.","ar":"قد تنجح الإزالة الميكانيكية لكنها تحتاج تكرارًا كل عدة أيام لأسابيع."},"reasoning":{"en":"The decisive clue is the need for meticulous repetition. This supports It is time-consuming and requires repeated sessions and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحاجة للتكرار الدقيق؛ ولذلك تدعم الإجابة «يستغرق وقتًا ويتطلب جلسات متكررة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q041","topic":"pediculosis","topicEn":"Pediculosis","topicAr":"القمل","type":"MCQ","difficulty":"Medium","source":"PDF p. 180","question":{"en":"Which statement about permethrin 5% for head lice is correct?","ar":"أي عبارة صحيحة عن بيرمثرين 5% لقمل الرأس؟"},"options":[{"letter":"A","en":"It is not more effective than permethrin 1% for routine head lice","ar":"ليس أكثر فعالية من بيرمثرين 1% في قمل الرأس المعتاد"},{"letter":"B","en":"It is mandatory for every child","ar":"إلزامي لكل طفل"},{"letter":"C","en":"It eliminates every nit with one application","ar":"يقضي على كل الصئبان بتطبيق واحد"},{"letter":"D","en":"It is the preferred body-lice decontamination method","ar":"هو وسيلة إزالة تلوث الملابس المفضلة"}],"correct":"A","explanation":{"en":"Increasing the concentration does not reliably overcome resistance or improve routine efficacy.","ar":"زيادة التركيز لا تتغلب بصورة موثوقة على المقاومة ولا تحسن الفعالية المعتادة."},"reasoning":{"en":"The decisive clue is lack of added efficacy at 5%. This supports It is not more effective than permethrin 1% for routine head lice and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي عدم وجود فائدة إضافية بتركيز 5%؛ ولذلك تدعم الإجابة «ليس أكثر فعالية من بيرمثرين 1% في قمل الرأس المعتاد» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q042","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 190","question":{"en":"Which vector transmits leishmaniasis?","ar":"ما الناقل الذي ينقل داء الليشمانيات؟"},"options":[{"letter":"A","en":"The male mosquito only","ar":"ذكر البعوض فقط"},{"letter":"B","en":"The infected female phlebotomine sandfly","ar":"أنثى ذبابة الرمل الفليبوتومية المصابة"},{"letter":"C","en":"A body louse","ar":"قمل الجسم"},{"letter":"D","en":"A scabies mite","ar":"عثة الجرب"}],"correct":"B","explanation":{"en":"The parasite is inoculated during the blood meal of an infected female sandfly.","ar":"يُحقن الطفيل أثناء وجبة دم لأنثى ذبابة الرمل المصابة."},"reasoning":{"en":"The decisive clue is the phlebotomine vector. This supports The infected female phlebotomine sandfly and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الناقل الفليبوتومي؛ ولذلك تدعم الإجابة «أنثى ذبابة الرمل الفليبوتومية المصابة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q043","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 190","question":{"en":"Which form of Leishmania is found within human macrophages?","ar":"أي طور من الليشمانيا يوجد داخل البلاعم البشرية؟"},"options":[{"letter":"A","en":"Cercariae","ar":"السركاريا"},{"letter":"B","en":"Microfilariae","ar":"الميكروفيلاريا"},{"letter":"C","en":"Amastigotes","ar":"الأماستيغوت"},{"letter":"D","en":"Trophozoites with cilia","ar":"تروفوزويتات مهدبة"}],"correct":"C","explanation":{"en":"Intracellular amastigotes multiply in macrophages in human tissue.","ar":"يتكاثر طور الأماستيغوت داخل البلاعم في أنسجة الإنسان."},"reasoning":{"en":"The decisive clue is intracellular macrophage infection. This supports Amastigotes and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العدوى داخل البلاعم؛ ولذلك تدعم الإجابة «الأماستيغوت» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q044","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 191","question":{"en":"What is the classic lesion of localized cutaneous leishmaniasis?","ar":"ما الآفة الكلاسيكية لليشمانيا الجلدية الموضعية؟"},"options":[{"letter":"A","en":"A painful dermatomal vesicular band","ar":"شريط حويصلي مؤلم قطعي"},{"letter":"B","en":"Diffuse honey-colored crusts","ar":"قشور عسلية منتشرة"},{"letter":"C","en":"A fleeting urticarial wheal","ar":"انتبار شرَوي عابر"},{"letter":"D","en":"A painless ulcer with an indurated raised border on exposed skin","ar":"قرحة غير مؤلمة بحافة مرتفعة متصلبة على جلد مكشوف"}],"correct":"D","explanation":{"en":"The lesion evolves from papule to nodule and ulcer, often with a firm raised edge.","ar":"تتطور الآفة من حطاطة إلى عقيدة ثم قرحة غالبًا بحافة صلبة مرتفعة."},"reasoning":{"en":"The decisive clue is the chronic painless indurated ulcer. This supports A painless ulcer with an indurated raised border on exposed skin and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي القرحة المزمنة غير المؤلمة المتصلبة؛ ولذلك تدعم الإجابة «قرحة غير مؤلمة بحافة مرتفعة متصلبة على جلد مكشوف» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q045","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 192","question":{"en":"What characterizes leishmaniasis recidivans?","ar":"ما الذي يميز الليشمانيا الناكسة؟"},"options":[{"letter":"A","en":"New papules around or within an old healed scar years later","ar":"حطاطات جديدة حول ندبة قديمة ملتئمة أو داخلها بعد سنوات"},{"letter":"B","en":"Acute generalized vesicles after one day","ar":"حويصلات معممة حادة بعد يوم"},{"letter":"C","en":"Only visceral disease without skin lesions","ar":"مرض حشوي فقط دون جلد"},{"letter":"D","en":"Rapid cure without treatment","ar":"شفاء سريع دون علاج"}],"correct":"A","explanation":{"en":"Recidivans is a chronic relapsing form, classically associated with L. tropica.","ar":"النوع الناكس شكل مزمن متكرر يرتبط تقليديًا بليشمانيا تروبيكا."},"reasoning":{"en":"The decisive clue is activity at the margin of an old scar. This supports New papules around or within an old healed scar years later and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي نشاط عند حافة ندبة قديمة؛ ولذلك تدعم الإجابة «حطاطات جديدة حول ندبة قديمة ملتئمة أو داخلها بعد سنوات» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q046","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 194","question":{"en":"Which pattern suggests diffuse cutaneous leishmaniasis?","ar":"أي نمط يوحي بالليشمانيا الجلدية المنتشرة؟"},"options":[{"letter":"A","en":"One small self-healing ulcer","ar":"قرحة صغيرة واحدة تلتئم ذاتيًا"},{"letter":"B","en":"Numerous widespread nonulcerating nodules with poor cell-mediated immunity","ar":"عقيدات منتشرة عديدة غير متقرحة مع ضعف المناعة الخلوية"},{"letter":"C","en":"Only nocturnal finger-web itch","ar":"حكة ليلية بين الأصابع فقط"},{"letter":"D","en":"Linear serpiginous tracks","ar":"مسارات خطية متعرجة"}],"correct":"B","explanation":{"en":"Diffuse disease produces widespread lesions and responds poorly because the host cannot contain the parasite.","ar":"يسبب المرض المنتشر آفات واسعة واستجابة ضعيفة بسبب عجز العائل عن احتواء الطفيل."},"reasoning":{"en":"The decisive clue is widespread nonulcerative nodules. This supports Numerous widespread nonulcerating nodules with poor cell-mediated immunity and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي العقيدات المنتشرة غير المتقرحة؛ ولذلك تدعم الإجابة «عقيدات منتشرة عديدة غير متقرحة مع ضعف المناعة الخلوية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q047","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 194","question":{"en":"Which feature is most concerning for mucosal leishmaniasis?","ar":"أي علامة تثير القلق أكثر من الليشمانيا المخاطية؟"},"options":[{"letter":"A","en":"Isolated dandruff","ar":"قشرة شعر منفردة"},{"letter":"B","en":"Nits on hair shafts","ar":"صئبان على الشعر"},{"letter":"C","en":"Progressive destructive lesions of the nose, mouth, or pharynx","ar":"آفات مدمرة متقدمة بالأنف أو الفم أو البلعوم"},{"letter":"D","en":"A single scabies burrow","ar":"نفق جرب واحد"}],"correct":"C","explanation":{"en":"Mucosal disease can destroy upper-airway structures and requires systemic treatment.","ar":"قد تدمر الليشمانيا المخاطية تراكيب مجرى الهواء العلوي وتحتاج علاجًا جهازيًا."},"reasoning":{"en":"The decisive clue is mucosal destruction. This supports Progressive destructive lesions of the nose, mouth, or pharynx and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي تخريب الأغشية المخاطية؛ ولذلك تدعم الإجابة «آفات مدمرة متقدمة بالأنف أو الفم أو البلعوم» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q048","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 191","question":{"en":"Which diagnostic method is generally the most sensitive for cutaneous leishmaniasis?","ar":"أي فحص هو الأكثر حساسية عمومًا لتشخيص الليشمانيا الجلدية؟"},"options":[{"letter":"A","en":"Routine urine dipstick","ar":"شريط فحص البول"},{"letter":"B","en":"Tzanck smear","ar":"مسحة تزانك"},{"letter":"C","en":"Patch testing","ar":"اختبار الرقعة"},{"letter":"D","en":"PCR or RT-PCR from lesion material","ar":"PCR أو RT-PCR من مادة الآفة"}],"correct":"D","explanation":{"en":"Molecular testing detects parasite DNA and is particularly useful in chronic or low-burden lesions.","ar":"يكشف الفحص الجزيئي DNA الطفيل ويفيد خاصة في الآفات المزمنة أو قليلة الحمل."},"reasoning":{"en":"The decisive clue is high molecular sensitivity when microscopy is negative. This supports PCR or RT-PCR from lesion material and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الحساسية الجزيئية العالية عند سلبية الميكروسكوب؛ ولذلك تدعم الإجابة «PCR أو RT-PCR من مادة الآفة» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q049","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 192","question":{"en":"Which profile is most compatible with uncomplicated localized cutaneous leishmaniasis?","ar":"أي وصف يتوافق أكثر مع ليشمانيا جلدية موضعية غير معقدة؟"},"options":[{"letter":"A","en":"An immunocompetent patient with one or a few small lesions away from high-risk sites and no mucosal risk","ar":"مريض سليم المناعة لديه آفة أو آفات قليلة صغيرة بعيدًا عن المواقع عالية الخطورة ودون خطر مخاطي"},{"letter":"B","en":"Multiple large facial lesions in an immunosuppressed patient","ar":"آفات وجهية كبيرة متعددة لدى مثبط المناعة"},{"letter":"C","en":"Mucosal symptoms after travel to a Viannia region","ar":"أعراض مخاطية بعد سفر لمنطقة فيانيا"},{"letter":"D","en":"A lesion larger than 5 cm with nodular lymphangitis","ar":"آفة أكبر من 5 سم مع التهاب لمفي عقدي"}],"correct":"A","explanation":{"en":"Limited low-risk lesions may be candidates for local therapy or observation depending on species.","ar":"قد تناسب الآفات المحدودة منخفضة الخطورة العلاج الموضعي أو الملاحظة حسب النوع."},"reasoning":{"en":"The decisive clue is small number, small size, low-risk location, intact immunity. This supports An immunocompetent patient with one or a few small lesions away from high-risk sites and no mucosal risk and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي قلة العدد وصغر الحجم وموقع منخفض الخطورة وسلامة المناعة؛ ولذلك تدعم الإجابة «مريض سليم المناعة لديه آفة أو آفات قليلة صغيرة بعيدًا عن المواقع عالية الخطورة ودون خطر مخاطي» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null},{"id":"Q050","topic":"leishmaniasis","topicEn":"Leishmaniasis","topicAr":"داء الليشمانيات","type":"MCQ","difficulty":"Medium","source":"PDF p. 192","question":{"en":"Which lesion location makes cutaneous leishmaniasis more likely to require systemic therapy?","ar":"أي موضع للآفة يجعل الليشمانيا الجلدية أكثر احتياجًا لعلاج جهازي؟"},"options":[{"letter":"A","en":"A tiny hidden lesion on the trunk only","ar":"آفة صغيرة مخفية على الجذع فقط"},{"letter":"B","en":"Face, eyelid, fingers, toes, or genital region","ar":"الوجه أو الجفن أو الأصابع أو أصابع القدم أو المنطقة التناسلية"},{"letter":"C","en":"One lesion already fully healed","ar":"آفة واحدة ملتئمة تمامًا"},{"letter":"D","en":"An asymptomatic scar with no activity","ar":"ندبة بلا أعراض أو نشاط"}],"correct":"B","explanation":{"en":"High-risk sites threaten function or cosmesis and are less suitable for destructive local therapy.","ar":"تهدد المواقع عالية الخطورة الوظيفة أو الشكل وتكون أقل ملاءمة للعلاج الموضعي المدمر."},"reasoning":{"en":"The decisive clue is the functionally and cosmetically critical location. This supports Face, eyelid, fingers, toes, or genital region and makes the other choices less appropriate.","ar":"العلامة الحاسمة هي الموقع الحرج وظيفيًا وتجميليًا؛ ولذلك تدعم الإجابة «الوجه أو الجفن أو الأصابع أو أصابع القدم أو المنطقة التناسلية» وتجعل الخيارات الأخرى أقل ملاءمة."},"image":null}];
